478	        if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;
479	        if (target.isContentEditable) return;
480	      }
481	      const fromMode = modeForHotkey(event.key);
482	      if (fromMode) {
483	        event.preventDefault();
484	        handleModeChange(fromMode);
485	        return;
486	      }
487	      if (event.key === '?') {
488	        event.preventDefault();
489	        setCheatsheetOpen((v) => !v);
490	        return;
491	      }
492	      if ((event.key === 'k' || event.key === 'K') && (event.metaKey || event.ctrlKey)) {
493	        event.preventDefault();
494	        setPaletteOpen((v) => !v);
495	        return;
496	      }
497	      // Tab cycling — Ctrl/⌘+Tab forward, Ctrl/⌘+Shift+Tab back.
498	      if (event.key === 'Tab' && (event.metaKey || event.ctrlKey)) {
499	        event.preventDefault();
500	        setTabsState((s) => cycleActive(s, event.shiftKey ? 'backward' : 'forward'));
501	        return;
502	      }
503	      // Close active tab — Ctrl/⌘+W.
504	      if ((event.key === 'w' || event.key === 'W') && (event.metaKey || event.ctrlKey)) {
505	        event.preventDefault();
506	        setTabsState((s) => (s.activeId ? closeTab(s, s.activeId) : s));
507	        return;
508	      }
509	      // Undo/Redo — Ctrl/⌘+Z / Ctrl/⌘+Shift+Z.
510	      if ((event.key === 'z' || event.key === 'Z') && (event.metaKey || event.ctrlKey)) {
511	        event.preventDefault();
512	        void handleUndoRedo(event.shiftKey ? false : true);
513	        return;
514	      }
515	      // V opens VV (Visibility/Graphics) dialog
516	      if (event.key === 'v' || event.key === 'V') {
517	        if (!event.metaKey && !event.ctrlKey && !event.altKey) {
