533	        if (legacy) {
534	          event.preventDefault();
535	          setPlanTool(legacy);
536	        }
537	      }
538	    };
539	    const onKeyUp = (event: globalThis.KeyboardEvent): void => {
540	      if (!event.shiftKey) setOrthoSnapHold(false);
541	    };
