import { create } from 'zustand';

type ActivityDrawerState = {
  isOpen: boolean;
  lastSeenAt: number;
  toggle: () => void;
  open: () => void;
  close: () => void;
  markSeen: () => void;
};

export const useActivityDrawerStore = create<ActivityDrawerState>((set) => ({
  isOpen: false,
