        >
          {filterChips.map(({ key, label }) => (
            <button
              key={key}
              type="button"
              data-testid={`activity-filter-${key}`}
              onClick={() => setFilter(key)}
              style={{
                padding: '2px 8px',
                borderRadius: 12,
                border: 'none',
                background: filter === key ? 'var(--surface-active)' : 'var(--surface-secondary)',
                color: filter === key ? 'var(--text-primary)' : 'var(--text-secondary)',
                fontSize: 'var(--text-2xs)',
                fontWeight: filter === key ? 600 : 400,
                cursor: 'pointer',
              }}
            >
              {label}
            </button>
          ))}
        </div>

        {/* Row list — latest 10 */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '4px 0' }}>
          {visible.length === 0 ? (
            <div
              style={{
                padding: 16,
                color: 'var(--text-tertiary)',
                fontSize: 'var(--text-2xs)',
                textAlign: 'center',
              }}
            >
              No activity yet.
            </div>
          ) : (
            visible.map((row) => (
              <DrawerRow
                key={row.id}
                row={row}
                travelled={travelledRow?.id === row.id}
                onTimeTravel={handleTimeTravel}
                onHoverChange={setHoveredRow}
              />
            ))
          )}
        </div>

        {/* Footer: see all */}
        <div
          style={{
            padding: '8px 12px',
            borderTop: '1px solid var(--border-subtle)',
            flexShrink: 0,
          }}
        >
          <button
            type="button"
            data-testid="activity-drawer-see-all"
            onClick={onSeeAll ?? onClose}
            style={{
              background: 'transparent',
              border: 'none',
              color: 'var(--text-secondary)',
              fontSize: 'var(--text-2xs)',
              cursor: 'pointer',
              padding: 0,
            }}
          >
            See all →
          </button>
        </div>
      </div>
    </>
  );
}

