39	  onLevelChange?: (id: string) => void;
40	  toolLabel?: string | null;
41	  /** Snap mode group; toggling individual snaps lives here. */
42	  snapModes?: { id: string; label: string; on: boolean }[];
43	  onSnapToggle?: (id: string) => void;
44	  gridOn?: boolean;
45	  onGridToggle?: () => void;
46	  /** Live cursor model coords, in mm; null when off-canvas. */
47	  cursorMm?: { xMm: number; yMm: number } | null;
48	  /** Undo depth; clicking the cluster invokes undo / redo. */
49	  undoDepth?: number;
50	  onUndo?: () => void;
51	  onRedo?: () => void;
52	  wsState?: StatusWsState;
53	  saveState?: StatusSaveState;
54	  conflictQueue?: CollaborationConflictQueueV1 | null;
55	  onClearConflict?: () => void;
56	  /** CHR-V3-03 slot 5 — lens discipline filter. */
57	  lensMode?: LensMode;
58	  onLensChange?: (lens: LensMode) => void;
59	  /** CHR-V3-03 slot 6 — federation drift count; hidden when 0. */
60	  driftCount?: number;
61	  onDriftClick?: () => void;
62	}
63	
64	export function StatusBar({
65	  level,
66	  levels = [],
67	  onLevelChange,
68	  toolLabel,
69	  snapModes = [],
70	  onSnapToggle,
71	  gridOn = true,
72	  onGridToggle,
73	  cursorMm,
74	  undoDepth,
75	  onUndo,
76	  onRedo,
77	  wsState = 'connected',
78	  saveState = 'saved',
79	  conflictQueue,
80	  onClearConflict,
81	  lensMode = 'all',
82	  onLensChange,
83	  driftCount = 0,
84	  onDriftClick,
85	}: StatusBarProps): JSX.Element {
86	  return (
87	    <div
88	      data-testid="status-bar"
89	      role="contentinfo"
90	      style={statusStyle}
91	      className="relative flex w-full items-center gap-3 border-t border-border bg-surface px-4 text-xs"
92	    >
93	      <LevelCluster level={level} levels={levels} onLevelChange={onLevelChange} />
94	      <Divider />
95	      <ToolCluster toolLabel={toolLabel ?? null} />
96	      <Divider />
97	      <SnapCluster snapModes={snapModes} onSnapToggle={onSnapToggle} />
98	      <Divider />
99	      <GridCluster gridOn={gridOn} onGridToggle={onGridToggle} />
100	      <Divider />
101	      <CoordCluster cursorMm={cursorMm ?? null} />
102	      <div className="ml-auto flex items-center gap-3">
103	        {conflictQueue ? (
104	          <>
105	            <ConflictSlot queue={conflictQueue} onClear={onClearConflict} />
106	            <Divider />
107	          </>
108	        ) : null}
109	        <UndoCluster depth={undoDepth ?? 0} onUndo={onUndo} onRedo={onRedo} />
110	        <Divider />
111	        <WsCluster state={wsState} />
112	        <Divider />
113	        <SaveCluster state={saveState} />
114	        <Divider />
115	        {/* Slot 5 — lens dropdown (CHR-V3-03 keystone, A8 antidote) */}
116	        <LensDropdown currentLens={lensMode} onLensChange={onLensChange ?? (() => {})} />
117	        {/* Slot 6 — drift badge; hidden when driftCount = 0 */}
118	        {driftCount > 0 ? (
119	          <>
120	            <Divider />
121	            <DriftBadge driftCount={driftCount} onClick={onDriftClick ?? (() => {})} />
122	          </>
123	        ) : null}
124	      </div>
125	    </div>
126	  );
