  /** CHR-V3-03 slot 6 — federation drift count; hidden when 0. */
  driftCount?: number;
  onDriftClick?: () => void;
  /** CHR-V3-05 slot 7 — activity-stream entry. */
  activityUnreadCount?: number;
  onActivityClick?: () => void;
}

