    }
    // Close active tab — Ctrl/⌘+W.
    if ((event.key === 'w' || event.key === 'W') && (event.metaKey || event.ctrlKey)) {
      event.preventDefault();
      setTabsState((s) => (s.activeId ? closeTab(s, s.activeId) : s));
